contracts/AidProgram.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.20;

contract AidProgram {
    struct Program {
        uint256 id;
        string name;
        string description;
        uint256 budget;
        uint256 startDate;
        uint256 endDate;
        bool active;
        address creator;
    }

    uint256 public nextProgramId = 1;
    mapping(uint256 => Program) public programs;
    mapping(uint256 => uint256) public allocatedVoucherCount;

    event ProgramCreated(uint256 indexed programId, address indexed creator, uint256 budget);
    event ProgramClosed(uint256 indexed programId);

    function createProgram(
        string calldata name,
        string calldata description,
        uint256 budget,
        uint256 startDate,
        uint256 endDate
    ) external returns (uint256) {
        require(budget > 0, "budget required");
        require(endDate > startDate, "invalid dates");

        uint256 programId = nextProgramId++;
        programs[programId] = Program({
            id: programId,
            name: name,
            description: description,
            budget: budget,
            startDate: startDate,
            endDate: endDate,
            active: true,
            creator: msg.sender
        });

        emit ProgramCreated(programId, msg.sender, budget);
        return programId;
    }

    function allocateVoucher(uint256 programId, uint256 count) external {
        Program memory program = programs[programId];
        require(program.id != 0, "program missing");
        require(program.active, "program closed");
        require(program.creator == msg.sender, "not owner");
        allocatedVoucherCount[programId] += count;
    }

    function closeProgram(uint256 programId) external {
        Program storage program = programs[programId];
        require(program.id != 0, "program missing");
        require(program.creator == msg.sender, "not owner");
        require(program.active, "already closed");

        program.active = false;
        emit ProgramClosed(programId);
    }
}

contracts/AidVoucher.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC1155/ERC1155.sol";

contract AidVoucher is ERC1155 {
    enum VoucherStatus {
        Issued,
        Redeemed,
        Expired,
        Cancelled
    }

    struct Voucher {
        uint256 id;
        uint256 programId;
        bytes32 beneficiaryHash;
        uint256 issuedAt;
        uint256 redeemedAt;
        uint256 expiresAt;
        VoucherStatus status;
    }

    uint256 public nextVoucherId = 1;
    mapping(uint256 => Voucher) public vouchers;

    event VoucherIssued(uint256 indexed voucherId, uint256 indexed programId, bytes32 beneficiaryHash);
    event VoucherRedeemed(uint256 indexed voucherId, uint256 redeemedAt);
    event VoucherBurned(uint256 indexed voucherId, address indexed holder, uint256 burnedAt);

    constructor() ERC1155("ipfs://proofaid-voucher/{id}.json") {}

    function issueVoucher(uint256 programId, bytes32 beneficiaryHash, uint256 expiryDays) external returns (uint256) {
        return issueVoucherTo(msg.sender, programId, beneficiaryHash, expiryDays);
    }

    function issueVoucherTo(
        address recipient,
        uint256 programId,
        bytes32 beneficiaryHash,
        uint256 expiryDays
    ) public returns (uint256) {
        require(recipient != address(0), "invalid recipient");
        require(beneficiaryHash != bytes32(0), "invalid beneficiary");
        require(expiryDays > 0, "invalid expiry");

        uint256 voucherId = nextVoucherId++;
        vouchers[voucherId] = Voucher({
            id: voucherId,
            programId: programId,
            beneficiaryHash: beneficiaryHash,
            issuedAt: block.timestamp,
            redeemedAt: 0,
            expiresAt: block.timestamp + (expiryDays * 1 days),
            status: VoucherStatus.Issued
        });

        _mint(recipient, voucherId, 1, "");
        emit VoucherIssued(voucherId, programId, beneficiaryHash);
        return voucherId;
    }

    function redeemVoucher(uint256 voucherId) external {
        Voucher storage voucher = vouchers[voucherId];
        require(voucher.id != 0, "voucher missing");
        require(voucher.status == VoucherStatus.Issued, "already consumed");
        require(balanceOf(msg.sender, voucherId) == 1, "holder required");

        if (block.timestamp > voucher.expiresAt) {
            voucher.status = VoucherStatus.Expired;
            revert("voucher expired");
        }

        _burn(msg.sender, voucherId, 1);
        voucher.status = VoucherStatus.Redeemed;
        voucher.redeemedAt = block.timestamp;
        emit VoucherBurned(voucherId, msg.sender, block.timestamp);
        emit VoucherRedeemed(voucherId, block.timestamp);
    }

    function burnExpiredVoucher(uint256 voucherId) external {
        Voucher storage voucher = vouchers[voucherId];
        require(voucher.id != 0, "voucher missing");
        require(voucher.status == VoucherStatus.Issued, "already consumed");
        require(block.timestamp > voucher.expiresAt, "not expired");
        require(balanceOf(msg.sender, voucherId) == 1, "holder required");

        _burn(msg.sender, voucherId, 1);
        voucher.status = VoucherStatus.Expired;
        emit VoucherBurned(voucherId, msg.sender, block.timestamp);
    }

    // Vouchers are non-transferable. They can only be minted and burned.
    function safeTransferFrom(address, address, uint256, uint256, bytes memory) public pure override {
        revert("voucher non-transferable");
    }

    function safeBatchTransferFrom(address, address, uint256[] memory, uint256[] memory, bytes memory) public pure override {
        revert("voucher non-transferable");
    }
}

contracts/BeneficiaryRegistry.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.20;

contract BeneficiaryRegistry {
    struct Beneficiary {
        bytes32 identityHash;
        uint256 programId;
        uint256 createdAt;
        bool active;
    }

    mapping(bytes32 => Beneficiary) public beneficiaries;

    event BeneficiaryRegistered(bytes32 indexed identityHash, uint256 indexed programId);

    function registerBeneficiary(bytes32 identityHash, uint256 programId) external {
        require(identityHash != bytes32(0), "invalid hash");
        require(beneficiaries[identityHash].createdAt == 0, "already exists");

        beneficiaries[identityHash] = Beneficiary({
            identityHash: identityHash,
            programId: programId,
            createdAt: block.timestamp,
            active: true
        });

        emit BeneficiaryRegistered(identityHash, programId);
    }
}

contracts/DistributionEvent.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.20;

contract DistributionEvent {
    struct EventRecord {
        uint256 id;
        uint256 programId;
        uint256 voucherId;
        bytes32 beneficiaryHash;
        uint256 timestamp;
        string status;
    }

    uint256 public nextEventId = 1;
    mapping(uint256 => EventRecord) public eventsById;

    event DistributionRecorded(uint256 indexed eventId, uint256 indexed voucherId, string status);

    function recordDistribution(
        uint256 programId,
        uint256 voucherId,
        bytes32 beneficiaryHash,
        string calldata status
    ) external returns (uint256) {
        uint256 eventId = nextEventId++;

        eventsById[eventId] = EventRecord({
            id: eventId,
            programId: programId,
            voucherId: voucherId,
            beneficiaryHash: beneficiaryHash,
            timestamp: block.timestamp,
            status: status
        });

        emit DistributionRecorded(eventId, voucherId, status);
        return eventId;
    }
}

